import re
import json

def convert_kml_coords(coord_text):
    """
    Converts KML coordinate string (lon,lat,alt) into [[lat, lon], ...]
    """

    points = re.split(r'\s+', coord_text.strip())
    result = []

    for point in points:
        parts = point.split(',')

        if len(parts) >= 2:
            lon = float(parts[0])
            lat = float(parts[1])
            result.append([lat, lon])

    return result


